+// sound_indicators.js
+// Provides ambient visual sound indicators near characters based on room activity.
+
+import { createElement, animateElement } from './utils/dom_helpers.js';
+
+// Icon SVGs for each sound type
+const ICONS = {
+  forge: `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
+    <line x1="2" y1="8" x2="14" y2="8" stroke="#d35400" stroke-width="2" stroke-linecap="round"/>
+    <line x1="4" y1="5" x2="4" y2="11" stroke="#e67e22" stroke-width="2" stroke-linecap="round"/>
+    <line x1="8" y1="3" x2="8" y2="13" stroke="#e67e22" stroke-width="2" stroke-linecap="round"/>
+    <line x1="12" y1="5" x2="12" y2="11" stroke="#e67e22" stroke-width="2" stroke-linecap="round"/>
+  </svg>`,
+  scribe: `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
+    <circle cx="5" cy="6" r="1.5" stroke="#2980b9" stroke-width="1.5"/>
+    <circle cx="9" cy="4" r="1" stroke="#3498db" stroke-width="1.5"/>
+    <circle cx="11" cy="8" r="1" stroke="#3498db" stroke-width="1.5"/>
+  </svg>`,
+  healer: `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
+    <circle cx="8" cy="8" r="6" stroke="#27ae60" stroke-width="1.5" opacity="0.7"/>
+    <circle cx="8" cy="8" r="4" stroke="#2ecc71" stroke-width="1.5" opacity="0.9"/>
+    <circle cx="8" cy="8" r="2" stroke="#27ae60" stroke-width="1.5"/>
+  </svg>`,
+  sentinel: `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
+    <text x="8" y="12" text-anchor="middle" font-size="14" fill="#c0392b" font-weight="bold">!</text>
+  </svg>`,
+};
+
+// Animation keyframes for each icon type
+const ANIMATIONS = {
+  forge: [
+    { transform: 'translateX(0) scale(1)', opacity: 1 },
+    { transform: 'translateX(3px) scale(1.1)', opacity: 0.7 },
+    { transform: 'translateX(0) scale(1)', opacity: 1 },
+  ],
+  scribe: [
+    { transform: 'translateY(0) scale(1)', opacity: 1 },
+    { transform: 'translateY(-3px) scale(1.2)', opacity: 0.8 },
+    { transform: 'translateY(0) scale(1)', opacity: 1 },
+  ],
+  healer: [
+    { transform: 'rotate(0deg) scale(1)', opacity: 0.8 },
+    { transform: 'rotate(15deg) scale(1.1)', opacity: 1 },
+    { transform: 'rotate(0deg) scale(1)', opacity: 0.8 },
+  ],
+  sentinel: [
+    { transform: 'scale(1)', opacity: 1 },
+    { transform: 'scale(1.3)', opacity: 0.6 },
+    { transform: 'scale(1)', opacity: 1 },
+  ],
+};
+
+const ANIMATION_OPTIONS = {
+  duration: 1200,
+  iterations: Infinity,
+  easing: 'ease-in-out',
+};
+
+// Main class to manage sound indicators
+export class SoundIndicators {
+  constructor(game) {
+    this.game = game;
+    this.indicators = new Map(); // characterId -> indicator element
+  }
+
+  update() {
+    const rooms = this.game.rooms;
+    // For each room, check activity and update indicators near characters
+    rooms.forEach(room => {
+      room.characters.forEach(char => {
+        const activity = this.getActivityForCharacter(room, char);
+        if (activity) {
+          this.showIndicator(char, activity);
+        } else {
+          this.hideIndicator(char);
+        }
+      });
+    });
+  }
+
+  getActivityForCharacter(room, character) {
+    // Determine activity type based on room activity and character role
+    // Prioritize: forge hammering > scribe writing > healer chanting > sentinel alert
+    if (room.activity.forgeHammering && character.role === 'blacksmith') {
+      return 'forge';
+    }
+    if (room.activity.scribeWriting && character.role === 'scribe') {
+      return 'scribe';
+    }
+    if (room.activity.healerChanting && character.role === 'healer') {
+      return 'healer';
+    }
+    if (room.activity.sentinelAlert && character.role === 'sentinel') {
+      return 'sentinel';
+    }
+    return null;
+  }
+
+  showIndicator(character, type) {
+    let indicator = this.indicators.get(character.id);
+    if (!indicator) {
+      indicator = createElement('div', 'sound-indicator');
+      indicator.style.position = 'absolute';
+      indicator.style.width = '16px';
+      indicator.style.height = '16px';
+      indicator.style.pointerEvents = 'none';
+      indicator.innerHTML = ICONS[type];
+      this.game.uiLayer.appendChild(indicator);
+      this.indicators.set(character.id, indicator);
+    }
+    indicator.innerHTML = ICONS[type];
+    // Position near character (top-right corner)
+    const pos = this.game.getCharacterScreenPosition(character);
+    indicator.style.left = `${pos.x + 12}px`;
+    indicator.style.top = `${pos.y - 8}px`;
+
+    // Animate icon
+    indicator.animate(ANIMATIONS[type], ANIMATION_OPTIONS);
+    indicator.style.display = 'block';
+  }
+
+  hideIndicator(character) {
+    const indicator = this.indicators.get(character.id);
+    if (indicator) {
+      indicator.style.display = 'none';
+      indicator.getAnimations().forEach(anim => anim.cancel());
+    }
+  }
+
+  clear() {
+    this.indicators.forEach(indicator => {
+      indicator.remove();
+    });
+    this.indicators.clear();
+  }
+}
+
